SELECT ?count WHERE {
  {
    SELECT(COUNT(?race) AS ?count) WHERE {
      wd:Q122865 wdt:P1275 ?race .
      ?race wdt:P1566 ?driver .
    }
    GROUP BY ?driver
    HAVING(COUNT(?race) < 17)
  } UNION {
    SELECT(COUNT(?race) AS ?count) WHERE {
      wd:Q122866 wdt:P1275 ?race .
      ?race wdt:P1566 ?driver .
    }
    GROUP BY ?driver
    HAVING(COUNT(?race) < 17)
  }
}
ORDER BY ?count
LIMIT 8

